sys_script_include.script:
var AROPTrigger = Class.create();
AROPTrigger.prototype = {
    initialize: function() {},

    fireNow: function() {
        // Find the AIROP scheduled job and set next_action to now
        // This fires it immediately without changing its regular schedule
        try {
            var job = new GlideRecord("sys_trigger");
            job.addQuery("name", "AIROP Scheduled Assessment");
            job.setLimit(1);
            job.query();
            if (!job.next()) {
                gs.error("[AIROP] Trigger: scheduled job not found");
                return false;
            }
            // Set next_action to now to fire immediately
            var now = new GlideDateTime();
            job.setValue("next_action", now);
            job.setValue("active", true);
            job.update();
            gs.log("[AIROP] Trigger: job scheduled to fire now - " + job.getUniqueValue());
            return true;
        } catch(e) {
            gs.error("[AIROP] Trigger error: " + e.message);
            return false;
        }
    },

    type: "AROPTrigger"
};
